+    // ==================== Drift Detection Tests ====================
+
+    use rch_telemetry::collect::cpu::{CpuTelemetry, LoadAverage};
+    use rch_telemetry::collect::memory::MemoryTelemetry;
+    use rch_telemetry::protocol::{TelemetrySource, WorkerTelemetry};
